  if(s.c2){set('name-2',s.c2.name);set('gender2',s.c2.gender);set('d2',s.c2.d);set('m2',s.c2.m);set('y2',s.c2.y);set('t2',s.c2.t);set('prov2',s.c2.prov);_customLng2=(typeof s.c2.lng==='number')?s.c2.lng:null;}
